#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        qsort(a, n, sizeof(int), compare);
        int ans = 0;
        for (int i = 0; i < n; i++) {
            ans += (a[i] / k) + ((a[i] % k) > 0);
        }
        printf("%d\n", ans);
    }
    return 0;
}

